/* ====================== STORAGE LAYER ======================
   Uses Claude artifact shared storage when available so captures
   sync across everyone using the app. Falls back to in-memory
   when opened as a standalone downloaded file. */
/* Three modes, auto-detected:
   1. Inside Claude  -> window.storage (shared:true) = live team sync.
   2. Hosted PWA     -> localStorage = persists on device, fully offline.
   3. Neither        -> in-memory (session only). */
const mem = {};
const hasStore = (typeof window !== 'undefined' && window.storage && typeof window.storage.get === 'function');
let hasLS = false;
try{ const t='__ccw_t'; localStorage.setItem(t,'1'); localStorage.removeItem(t); hasLS = true; }catch(e){ hasLS = false; }
const SYNC = hasStore;            // true only when team-sync is active
const PERSIST = hasStore || hasLS; // data survives reloads

async function loadKey(key){
  if(hasStore){
    try{ const r = await window.storage.get(key, true); return r && r.value ? JSON.parse(r.value) : []; }
    catch(e){ return []; }
  }
  if(hasLS){
    try{ const v = localStorage.getItem(key); return v ? JSON.parse(v) : []; }catch(e){ return []; }
  }
  return mem[key] ? JSON.parse(JSON.stringify(mem[key])) : [];
}
async function saveKey(key, arr){
  if(hasStore){ try{ await window.storage.set(key, JSON.stringify(arr), true); }catch(e){} return; }
  if(hasLS){ try{ localStorage.setItem(key, JSON.stringify(arr)); }catch(e){} return; }
  mem[key] = arr;
}
async function loadIdentity(){
  if(hasStore){ try{ const r = await window.storage.get('ccw:identity', false); return r && r.value ? JSON.parse(r.value) : null; }catch(e){ return null; } }
  if(hasLS){ try{ const v = localStorage.getItem('ccw:identity'); return v ? JSON.parse(v) : null; }catch(e){ return null; } }
  return mem['__id'] || null;
}
async function saveIdentity(id){
  if(hasStore){ try{ await window.storage.set('ccw:identity', JSON.stringify(id), false); }catch(e){} return; }
  if(hasLS){ try{ id ? localStorage.setItem('ccw:identity', JSON.stringify(id)) : localStorage.removeItem('ccw:identity'); }catch(e){} return; }
  mem['__id']=id;
}

/* ====================== STATE ====================== */
const K = { notes:'ccw:notes', jots:'ccw:jots', contacts:'ccw:contacts', actions:'ccw:actions' };
let DB = { notes:[], jots:[], contacts:[], actions:[] };
let ME = null;
let tab='home', exhFilter='all', capTab='note', capScope='all', fuFilter='all';
const SHEET_URL = 'https://docs.google.com/spreadsheets/d/1XCzMTbOeijHnWjn9k6_ZogjVV4kblLiXii58MHjxhJs/edit?gid=1877908216#gid=1877908216';

function uid(){ return Date.now().toString(36)+Math.random().toString(36).slice(2,6); }
function initials(n){ return (n||'?').trim().split(/\s+/).map(w=>w[0]).slice(0,2).join('').toUpperCase(); }
function esc(s){ return (s||'').replace(/[&<>"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[c])); }
function ago(ts){
  const d=Date.now()-ts; const m=Math.floor(d/60000);
  if(m<1) return 'just now'; if(m<60) return m+'m'; const h=Math.floor(m/60);
  if(h<24) return h+'h'; return Math.floor(h/24)+'d';
}

/* ====================== LOGIN ====================== */
function doLogin(){
  const name=document.getElementById('li-name').value.trim();
  const email=document.getElementById('li-email').value.trim().toLowerCase();
  const err=document.getElementById('li-err');
  err.className='err';
  if(!name){ err.textContent='Please enter your name.'; err.classList.add('show'); return; }
  if(!/^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email)){ err.textContent='Enter a valid email address.'; err.classList.add('show'); return; }
  if(!email.includes('datavoice')){ err.textContent='A Datavoice email is required to confirm folder access.'; err.classList.add('show'); return; }
  ME={ name, email };
  saveIdentity(ME);
  enterApp();
}
function enterApp(){
  document.getElementById('login').style.display='none';
  document.getElementById('app').style.display='block';
  document.getElementById('whoami').textContent=initials(ME.name);
  document.getElementById('greet-name').textContent=ME.name.split(' ')[0];
  const h=new Date().getHours();
  document.getElementById('greet').textContent = h<12?'Good morning':h<18?'Good afternoon':'Good evening';
  document.getElementById('sheet-link').href=SHEET_URL;
  renderAll();
}

/* ====================== NAV ====================== */
function go(t){
  tab=t;
  document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));
  document.getElementById('s-'+t).classList.add('active');
  document.querySelectorAll('nav.tabs button').forEach(b=>b.classList.toggle('on', b.dataset.t===t));
  window.scrollTo(0,0);
  document.getElementById('fab').style.display = (t==='exh'||t==='mtg') ? 'none' : 'grid';
}
function fabAction(){
  if(tab==='fu') openCapture('action');
  else if(tab==='cap') openCapture(capTab);
  else openCapture('note');
}

/* ====================== RENDER ALL ====================== */
function renderAll(){ renderHome(); renderExh(); renderMtg(); renderCap(); renderFU(); }

/* ---------- HOME ---------- */
function renderHome(){
  const stats=[
    {n:SEED.exhibitors.length,l:'Exhibitors',a:'var(--cyan)'},
    {n:SEED.meetings.length,l:'Meetings',a:'var(--amber)'},
    {n:DB.actions.filter(a=>a.status!=='done').length,l:'Open follow-ups',a:'var(--teal)'},
    {n:DB.notes.length+DB.jots.length,l:'Floor captures',a:'#ef9f53'},
  ];
  document.getElementById('home-stats').innerHTML=stats.map(s=>
    `<div class="tile" style="--accent:${s.a}"><div class="n">${s.n}</div><div class="l">${s.l}</div></div>`).join('');

  const flagged=SEED.exhibitors.filter(e=>e.note).slice(0,6);
  document.getElementById('home-flagged').innerHTML=flagged.map(e=>rowHTML(e)).join('');

  const feed=[
    ...DB.notes.map(x=>({...x,_t:'note'})),
    ...DB.jots.map(x=>({...x,_t:'jot'})),
    ...DB.actions.map(x=>({...x,_t:'action'})),
  ].sort((a,b)=>b.createdAt-a.createdAt).slice(0,4);
  document.getElementById('home-feed').innerHTML = feed.length
    ? feed.map(feedCardHTML).join('')
    : emptyHTML('Nothing captured yet','Tap a quick-capture button to start.');
}

/* ---------- EXHIBITORS ---------- */
function exhTags(e){
  let t='';
  const n=(e.note||'').toLowerCase();
  if(n.includes('competitor')) t+='<span class="badge comp">Competitor</span>';
  else if(e.note) t+='<span class="badge flag">Intel</span>';
  if(DB.actions.some(a=>a.company===e.name)) t+='<span class="badge lead">Follow-up</span>';
  if(DB.notes.some(x=>x.company===e.name)) t+='<span class="badge ghost">Noted</span>';
  return t;
}
function rowHTML(e){
  return `<button class="row" onclick='openExhibitor(${JSON.stringify(e.name)})'>
    <div class="stand">${esc(e.stand||'—')}</div>
    <div class="meta"><b>${esc(e.name)}</b><div class="tags">${exhTags(e)}</div></div>
    <svg class="chev" viewBox="0 0 24 24" width="18" height="18" fill="none" stroke="currentColor" stroke-width="2"><path d="M9 6l6 6-6 6"/></svg>
  </button>`;
}
function renderExh(){
  const chips=[['all','All'],['intel','Intel'],['competitor','Competitors'],['tracked','Tracked']];
  document.getElementById('exh-chips').innerHTML=chips.map(([k,l])=>
    `<button class="chip ${exhFilter===k?'on':''}" onclick="setExhFilter('${k}')">${l}</button>`).join('');
  const q=(document.getElementById('exh-q').value||'').toLowerCase();
  let list=SEED.exhibitors.filter(e=>{
    if(q && !(e.name.toLowerCase().includes(q)||(e.stand||'').toLowerCase().includes(q))) return false;
    const n=(e.note||'').toLowerCase();
    if(exhFilter==='intel' && !e.note) return false;
    if(exhFilter==='competitor' && !n.includes('competitor')) return false;
    if(exhFilter==='tracked' && !(DB.actions.some(a=>a.company===e.name)||DB.notes.some(x=>x.company===e.name))) return false;
    return true;
  });
  document.getElementById('exh-list').innerHTML = list.length
    ? `<div class="faint mono" style="font-size:11px;margin-bottom:10px">${list.length} ${list.length===1?'STAND':'STANDS'}</div>`+list.map(rowHTML).join('')
    : emptyHTML('No matches','Try a different search or filter.');
}
function setExhFilter(k){ exhFilter=k; renderExh(); }

/* ---------- MEETINGS ---------- */
function renderMtg(){
  const q=(document.getElementById('mtg-q').value||'').toLowerCase();
  let list=SEED.meetings.filter(m=> !q || (m.who+' '+m.topic+' '+m.dvWho).toLowerCase().includes(q));
  document.getElementById('mtg-list').innerHTML = list.length ? list.map((m,i)=>{
    const when=m.time && m.time.toLowerCase()!=='not available' ? m.time : 'TBA';
    const tba=when==='TBA'?'tba':'';
    const extras=DB.actions.filter(a=>a.meetingRef===m.who);
    return `<div class="mtg">
      <div class="top"><div class="nm">${esc(m.who)}</div><div class="when ${tba}">${esc(when)}</div></div>
      ${m.topic?`<div class="topic">${esc(m.topic)}</div>`:''}
      <div class="leads">
        ${m.dvWho?`<span class="badge lead">DV · ${esc(m.dvWho)}</span>`:''}
        ${m.requestedBy?`<span class="badge ghost">Req: ${esc(m.requestedBy)}</span>`:''}
        ${m.address?`<span class="badge ghost">${esc(m.address)}</span>`:''}
      </div>
      ${m.objections?`<div class="topic faint" style="margin-top:7px">⚑ ${esc(m.objections)}</div>`:''}
      ${extras.length?`<div style="margin-top:10px">${extras.map(a=>`<div class="act">✓ ${esc(a.task)} <span class="faint">— ${esc(a.author)}</span></div>`).join('')}</div>`:''}
      <button class="btn ghost sm" style="margin-top:12px" onclick='openCapture("action",{meetingRef:${JSON.stringify(m.who)},company:${JSON.stringify(m.who)}})'>+ Add follow-up</button>
    </div>`;
  }).join('') : emptyHTML('No meetings found','Adjust your search.');
}

/* ---------- CAPTURE ---------- */
function setCapTab(k){ capTab=k; document.querySelectorAll('#cap-seg button').forEach(b=>b.classList.toggle('on',b.dataset.k===k)); renderCap(); }
function setScope(s){ capScope=s; document.querySelectorAll('#cap-scope button').forEach(b=>b.classList.toggle('on',b.dataset.s===s)); renderCap(); }
function feedCardHTML(x){
  const isMe = x.authorEmail===ME.email;
  let body='';
  if(x._t==='note'){
    body=`${x.company?`<div class="comp">${esc(x.company)}</div>`:''}<div class="txt">${esc(x.notes)}</div>${x.actions?`<div class="act">→ ${esc(x.actions)}</div>`:''}`;
  } else if(x._t==='jot'){
    body=`<div class="txt">${esc(x.text)}</div>`;
  } else if(x._t==='contact'){
    body=`<div class="comp">${esc(x.name)}</div><div class="txt faint">${esc([x.role,x.company].filter(Boolean).join(' · '))}</div>${x.email||x.phone?`<div class="act" style="color:var(--cyan)">${esc([x.email,x.phone].filter(Boolean).join('  ·  '))}</div>`:''}`;
  } else if(x._t==='action'){
    const cls={open:'s-open','in progress':'s-progress',done:'s-done'}[x.status]||'s-open';
    body=`${x.company?`<div class="comp">${esc(x.company)}</div>`:''}<div class="txt">${esc(x.task)}</div>${x.description?`<div class="txt faint" style="font-size:12.5px;margin-top:3px">${esc(x.description)}</div>`:''}
    <div style="display:flex;gap:8px;align-items:center;margin-top:9px;flex-wrap:wrap"><span class="status-pill ${cls}">${esc(x.status)}</span>${x.dvLead?`<span class="badge lead">${esc(x.dvLead)}</span>`:''}</div>`;
  }
  const tag={note:'NOTE',jot:'JOT',contact:'CONTACT',action:'FOLLOW-UP'}[x._t];
  return `<div class="feed-card">
    ${isMe?`<button class="del" onclick="delItem('${x._t}','${x.id}')"><svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18M8 6V4h8v2M6 6l1 14h10l1-14"/></svg></button>`:''}
    <div class="hd"><div class="who">${initials(x.author)}</div><div class="nm">${esc(x.author)}</div><div class="tm">${tag} · ${ago(x.createdAt)}</div></div>
    ${body}
  </div>`;
}
function renderCap(){
  const arr=(capTab==='note'?DB.notes:capTab==='jot'?DB.jots:DB.contacts)
    .filter(x=>capScope==='all'||x.authorEmail===ME.email)
    .sort((a,b)=>b.createdAt-a.createdAt);
  const names={note:['notes','Add a note about a conversation or stand visit.'],jot:['jots','A quick reminder to look at later.'],contact:['contacts','Save people you meet on the floor.']};
  document.getElementById('cap-list').innerHTML = arr.length
    ? arr.map(x=>feedCardHTML({...x,_t:capTab})).join('')
    : emptyHTML('No '+names[capTab][0]+' yet', names[capTab][1]);
}

/* ---------- FOLLOW-UPS ---------- */
function renderFU(){
  const chips=[['all','All'],['open','Open'],['in progress','In progress'],['done','Done'],['mine','Mine']];
  document.getElementById('fu-chips').innerHTML=chips.map(([k,l])=>{
    const c = k==='all'?DB.actions.length : k==='mine'?DB.actions.filter(a=>a.authorEmail===ME.email).length : DB.actions.filter(a=>a.status===k).length;
    return `<button class="chip ${fuFilter===k?'on':''}" onclick="setFU('${k}')">${l} ${c?`· ${c}`:''}</button>`;
  }).join('');
  let arr=DB.actions.filter(a=>{
    if(fuFilter==='all') return true;
    if(fuFilter==='mine') return a.authorEmail===ME.email;
    return a.status===fuFilter;
  }).sort((a,b)=>(a.status==='done')-(b.status==='done') || b.createdAt-a.createdAt);
  document.getElementById('fu-list').innerHTML = arr.length ? arr.map(a=>{
    const cls={open:'s-open','in progress':'s-progress',done:'s-done'}[a.status]||'s-open';
    const isMe=a.authorEmail===ME.email;
    return `<div class="feed-card">
      ${isMe?`<button class="del" onclick="delItem('action','${a.id}')"><svg viewBox="0 0 24 24" width="15" height="15" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 6h18M8 6V4h8v2M6 6l1 14h10l1-14"/></svg></button>`:''}
      <div class="hd"><div class="who">${initials(a.author)}</div><div class="nm">${esc(a.author)}</div><div class="tm">${ago(a.createdAt)}</div></div>
      ${a.company?`<div class="comp">${esc(a.company)}</div>`:''}
      <div class="txt">${esc(a.task)}</div>
      ${a.description?`<div class="txt faint" style="font-size:12.5px;margin-top:3px">${esc(a.description)}</div>`:''}
      <div style="display:flex;gap:7px;align-items:center;margin-top:11px;flex-wrap:wrap">
        ${a.dvLead?`<span class="badge lead">${esc(a.dvLead)}</span>`:''}
        <div style="margin-left:auto;display:flex;gap:5px">
          ${['open','in progress','done'].map(s=>`<button onclick="cycleStatus('${a.id}','${s}')" class="status-pill ${a.status===s?cls:''}" style="${a.status===s?'':'background:var(--bg2);color:var(--ink-faint);border:1px solid var(--line)'}">${s==='in progress'?'WIP':s.toUpperCase()}</button>`).join('')}
        </div>
      </div>
    </div>`;
  }).join('') : emptyHTML('No follow-ups','Assign an action and the whole team sees it here.');
}
function setFU(k){ fuFilter=k; renderFU(); }
async function cycleStatus(id,s){
  const a=DB.actions.find(x=>x.id===id); if(!a) return;
  a.status=s; await saveKey(K.actions,DB.actions); renderFU(); renderHome(); toast('Status updated');
}

