/* ====================== CAPTURE FORMS ====================== */
function fieldCompany(pre){
  return `<div class="field"><label>Company / stand</label>
    <input id="f-company" list="exh-dl" placeholder="Start typing…" value="${esc(pre||'')}">
    <datalist id="exh-dl">${SEED.exhibitors.map(e=>`<option value="${esc(e.name)}">`).join('')}</datalist></div>`;
}
function openCapture(kind, pre){
  pre=pre||{};
  closeSheet();
  setTimeout(()=>{
    let title,body;
    if(kind==='note'){
      title='New note';
      body=fieldCompany(pre.company)+
        `<div class="field"><label>Who / contact</label><input id="f-who" placeholder="Person spoken to"></div>
         <div class="field"><label>Notes</label><textarea id="f-notes" placeholder="What was discussed…" autofocus>${esc(pre.text||'')}</textarea></div>
         <div class="field"><label>Action needed (optional)</label><input id="f-actions" placeholder="Next step"></div>`;
    } else if(kind==='jot'){
      title='Quick jot';
      body=`<div class="field"><label>Tag (optional)</label><input id="f-tag" placeholder="e.g. MSI, L3Harris"></div>
            <div class="field"><label>Jot</label><textarea id="f-text" placeholder="Something to remember…">${esc(pre.text||'')}</textarea><div class="hint">A quick reminder to look at later.</div></div>`;
    } else if(kind==='contact'){
      title='New contact';
      body=`<div class="scan-row">
              <button onclick="openScanner()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M3 7V5a2 2 0 0 1 2-2h2M17 3h2a2 2 0 0 1 2 2v2M21 17v2a2 2 0 0 1-2 2h-2M7 21H5a2 2 0 0 1-2-2v-2"/><path d="M7 12h10"/></svg>Scan QR</button>
              <button onclick="document.getElementById('qr-file').click()"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><rect x="3" y="3" width="18" height="18" rx="2"/><circle cx="9" cy="9" r="2"/><path d="M21 15l-5-5L5 21"/></svg>From photo</button>
            </div>
            <div class="field"><label>Name</label><input id="f-name" placeholder="Full name"></div>
            <div class="field"><label>Role / title</label><input id="f-role" placeholder="e.g. Pre-sales Director"></div>`+
            fieldCompany(pre.company)+
           `<div class="field"><label>Email</label><input id="f-email" type="email" inputmode="email" placeholder="name@company.com"></div>
            <div class="field"><label>Phone</label><input id="f-phone" type="tel" inputmode="tel" placeholder="+…"></div>`;
    } else if(kind==='action'){
      title='New follow-up';
      body=fieldCompany(pre.company)+
        `<div class="field"><label>Task</label><input id="f-task" placeholder="What needs to happen"></div>
         <div class="field"><label>Description (optional)</label><textarea id="f-desc" placeholder="Detail / context"></textarea></div>
         <div class="field"><label>DV lead</label><input id="f-lead" placeholder="Who owns it" value="${esc(ME.name.split(' ')[0])}"></div>
         <div class="field"><label>Status</label>
           <div class="opts" id="f-status"><button class="on" data-v="open">Open</button><button data-v="in progress">In progress</button><button data-v="done">Done</button></div></div>`;
      if(pre.meetingRef) body+=`<input type="hidden" id="f-mref" value="${esc(pre.meetingRef)}">`;
    }
    const html=`<div class="sheet-hd"><h3>${title}</h3><button class="x" onclick="closeSheet()">✕</button></div>
      <div class="sheet-body">${body}
        <button class="btn" onclick="saveCapture('${kind}')">Save${SYNC?' &amp; share with team':''}</button>
        <div style="height:6px"></div></div>`;
    openSheetHTML(html);
    // status toggle
    const st=document.getElementById('f-status');
    if(st) st.querySelectorAll('button').forEach(b=>b.onclick=()=>{st.querySelectorAll('button').forEach(x=>x.classList.remove('on'));b.classList.add('on');});
    const first=document.querySelector('.sheet input,.sheet textarea'); if(first) setTimeout(()=>first.focus(),250);
  },kind&&document.getElementById('sheet').classList.contains('show')?260:0);
}
function val(id){ const el=document.getElementById(id); return el?el.value.trim():''; }
async function saveCapture(kind){
  const base={ id:uid(), author:ME.name, authorEmail:ME.email, createdAt:Date.now() };
  if(kind==='note'){
    const notes=val('f-notes'); if(!notes){ shake(); return; }
    DB.notes.push({...base, company:val('f-company'), who:val('f-who'), notes, actions:val('f-actions')});
    await saveKey(K.notes,DB.notes);
  } else if(kind==='jot'){
    const text=val('f-text'); if(!text){ shake(); return; }
    DB.jots.push({...base, tag:val('f-tag'), text});
    await saveKey(K.jots,DB.jots);
  } else if(kind==='contact'){
    const name=val('f-name'); if(!name){ shake(); return; }
    DB.contacts.push({...base, name, role:val('f-role'), company:val('f-company'), email:val('f-email'), phone:val('f-phone')});
    await saveKey(K.contacts,DB.contacts);
  } else if(kind==='action'){
    const task=val('f-task'); if(!task){ shake(); return; }
    const stBtn=document.querySelector('#f-status button.on');
    DB.actions.push({...base, company:val('f-company'), task, description:val('f-desc'), dvLead:val('f-lead'), status:stBtn?stBtn.dataset.v:'open', meetingRef:val('f-mref')});
    await saveKey(K.actions,DB.actions);
  }
  closeSheet(); renderAll();
  toast(SYNC?'Saved & shared with the team':'Saved');
}
async function delItem(type,id){
  const map={note:K.notes,jot:K.jots,contact:K.contacts,action:K.actions};
  const arrName={note:'notes',jot:'jots',contact:'contacts',action:'actions'}[type];
  DB[arrName]=DB[arrName].filter(x=>x.id!==id);
  await saveKey(map[type],DB[arrName]);
  renderAll(); toast('Deleted');
}

